class AuthService {
  Future<void> login({
    required String email,
    required String password,
  }) async {
    AppLogger.authFlow(
      step: 'login_start',
      email: email,
      password: password,
    );

    try {
      final response = await http.post(
        Uri.parse('https://example.com/api/login'),
        headers: {
          'Content-Type': 'application/json',
        },
        body: jsonEncode({
          'email': email,
          'password': password,
        }),
      );

      AppLogger.authFlow(
        step: 'login_response',
        email: email,
        extra: {
          'statusCode': response.statusCode,
          'body': response.body,
        },
      );
    } catch (e, st) {
      AppLogger.log(
        'Login failed',
        level: LogLevel.error,
        tag: 'AUTH',
        error: e,
        stackTrace: st,
      );
      rethrow;
    }
  }
}

